        // Per-game overrides for MegaloSchema.Enums. The Reach schema was
        // generated from Reach var enums.xml and has tag/variant layouts
        // that diverge from H2A (notably NumericTypeRef inserts Scratch.Number
        // at tag 5, shifting later variants by 1+). ReadSchemaEnum consults
        // this dict first when ctx.Game == H2A.
        public static readonly IReadOnlyDictionary<string, EnumDef> H2AEnums = BuildH2AEnums();

        private static IReadOnlyDictionary<string, EnumDef> BuildH2AEnums()
        {
            var d = new Dictionary<string, EnumDef>(StringComparer.OrdinalIgnoreCase);

            // NumericTypeRef — 7-bit tag; first 16 variants have distinct
            // shapes per Halo 2A/var enums.xml:25-78. Remaining 112 variants
            // (tags 16-127) are leaf with 0 payload bits, so we enumerate
            // them by index + synthesized name.
            var numVariants = new List<VariantDef>
            {
                new VariantDef("Int16", "Int16", 0, "0000000", new[] {
                    new FieldDef("Int16", "Int", 16) }),
                new VariantDef("Player.Number", "Player.Number", 1, "0000001", new[] {
                    new FieldDef("Player", "Enumref:PlayerRef", 0),
                    new FieldDef("PlayerNum", "Ref0:Gametype/base/mpvr/megl/MegaloVars/PlayerVars/playernumbers", 4) }),
                new VariantDef("Object.Number", "Object.Number", 2, "0000010", new[] {
                    new FieldDef("Object", "Enumref:ObjectRef", 0),
                    new FieldDef("ObjectNum", "Ref0:Gametype/base/mpvr/megl/MegaloVars/ObjectVars/objectnumbers", 4) }),
                new VariantDef("Team.Number", "Team.Number", 3, "0000011", new[] {
                    new FieldDef("Team", "Enumref:TeamRef", 0),
                    new FieldDef("TeamNum", "Ref0:Gametype/base/mpvr/megl/MegaloVars/TeamVars/teamnumbers", 4) }),
                new VariantDef("Global.Number", "Global.Number", 4, "0000100", new[] {
                    new FieldDef("GlobalNum", "Ref0:Gametype/base/mpvr/megl/MegaloVars/GlobalVars/globalnumbers", 5) }),
                new VariantDef("Scratch.Number", "Scratch.Number", 5, "0000101", new[] {
                    new FieldDef("ScratchNum", "Enumref:ScratchNumericRef", 0) }),
                new VariantDef("ScriptOption", "ScriptOption", 6, "0000110", new[] {
                    new FieldDef("Option", "Ref0:Gametype/base/mpvr/ScriptOptions", 4) }),
                new VariantDef("Object.SpawnSeq", "Object.SpawnSeq", 7, "0000111", new[] {
                    new FieldDef("Object", "Enumref:ObjectRef", 0) }),
                new VariantDef("Object.UserData", "Object.UserData", 8, "0001000", new[] {
                    new FieldDef("Object", "Enumref:ObjectRef", 0) }),
                new VariantDef("ObjVal.Unk9", "ObjVal.Unk9", 9, "0001001", new[] {
                    new FieldDef("Object", "Enumref:ObjectRef", 0) }),
                new VariantDef("Team.Score", "Team.Score", 10, "0001010", new[] {
                    new FieldDef("Team", "Enumref:TeamRef", 0) }),
                new VariantDef("Player.Score", "Player.Score", 11, "0001011", new[] {
                    new FieldDef("Player", "Enumref:PlayerRef", 0) }),
                new VariantDef("Player.Money", "Player.Money", 12, "0001100", new[] {
                    new FieldDef("Player", "Enumref:PlayerRef", 0) }),
                new VariantDef("Player.Rating", "Player.Rating", 13, "0001101", new[] {
                    new FieldDef("Player", "Enumref:PlayerRef", 0) }),
                new VariantDef("Player.Stat", "Player.Stat", 14, "0001110", new[] {
                    new FieldDef("Player", "Enumref:PlayerRef", 0),
                    new FieldDef("Statistic", "Ref0:Gametype/base/mpvr/megl/playerstats", 2) }),
                new VariantDef("Team.Stat", "Team.Stat", 15, "0001111", new[] {
                    new FieldDef("Team", "Enumref:TeamRef", 0),
                    new FieldDef("Statistic", "Ref0:Gametype/base/mpvr/megl/playerstats", 2) }),
            };
            // Tags 16..22 — specific names per XML; all leaf (no fields).
            string[] named16Plus = {
                "Unk16", "CurrentRound", "SymmetricMode", "SymmetricModeWritable",
                "Gamemode Controls Victory Enabled", "ScoreToWinGame",
            };
            for (int i = 0; i < named16Plus.Length; i++)
                numVariants.Add(new VariantDef(named16Plus[i], named16Plus[i], 16 + i,
                    Convert.ToString(16 + i, 2).PadLeft(7, '0'), Array.Empty<FieldDef>()));
            // Tags 22..31 have Team/Player scalar fields (LivesLeft, SpawnDelay,
            // UnkVal25-32). From Halo 2A/var enums.xml:87-119.
            var t22Plus = new (string name, string refType)[]
            {
                ("Team.LivesLeft", "Enumref:TeamRef"),
                ("Player.LivesLeft", "Enumref:PlayerRef"),
                ("Player.SpawnDelay", "Enumref:PlayerRef"),
                ("Player.UnkVal25", "Enumref:PlayerRef"),
                ("Player.UnkVal26", "Enumref:PlayerRef"),
                ("Player.UnkVal27", "Enumref:PlayerRef"),
                ("Team.UnkVal28", "Enumref:TeamRef"),
                ("Team.UnkVal29", "Enumref:TeamRef"),
                ("Team.UnkVal30", "Enumref:TeamRef"),
                ("Object.UnkVal31", "Enumref:ObjectRef"),
                ("Object.UnkVal32", "Enumref:ObjectRef"),
            };
            for (int i = 0; i < t22Plus.Length; i++)
            {
                int tag = 22 + i;
                var fieldName = t22Plus[i].refType switch {
                    "Enumref:PlayerRef" => "Player",
                    "Enumref:TeamRef" => "Team",
                    "Enumref:ObjectRef" => "Object",
                    _ => "Ref",
                };
                numVariants.Add(new VariantDef(t22Plus[i].name, t22Plus[i].name, tag,
                    Convert.ToString(tag, 2).PadLeft(7, '0'),
                    new[] { new FieldDef(fieldName, t22Plus[i].refType, 0) }));
            }
            // Tags 33..127 are leaf (no payload bits) in H2A per the XML —
            // all "Unlabelled" or simple named constants. Synthesize.
            for (int tag = 33; tag < 128; tag++)
            {
                if (numVariants.Exists(v => v.Id == tag)) continue;
                string tagBits = Convert.ToString(tag, 2).PadLeft(7, '0');
                numVariants.Add(new VariantDef("Unlabelled", $"Unlabelled_{tag}", tag, tagBits,
                    Array.Empty<FieldDef>()));
            }
            d["NumericTypeRef"] = new EnumDef("NumericTypeRef", 7, numVariants.ToArray());

            // VarType / PlayerTypeRef / ObjectTypeRef / TeamTypeRef / TimerTypeRef
            // intentionally NOT overridden here — Megalograph XML's definitions
            // (in MegaloSchema.Enums via Reach) match H2A widths and structures.
            return d;
        }

        // Full H2A gametype variant layout (mpvr container) — FileHeader
        // through WeaponTunings. Walked by GametypeReader from bit 752 of
        // the raw .bin when the magic at that offset is "mpvr".
        public static readonly MegaloSection[] H2AMpvrLayout = BuildH2AMpvrLayout();

        // Full H2A forge-variant layout (gvar container). Header is 224
        // bits shorter than mpvr — gvar omits UnknownHash0x2FC (160 bits),
        // Blank0x310 (32 bits) and Fileusedsize (32 bits). Walked from
        // bit 1024 (byte 128) of the raw .bin when the magic there is "gvar".
        public static readonly MegaloSection[] H2AGvarLayout = BuildH2AGvarLayout();

        // H2A post-trigger script + mpvr tail layout, walked by the
        // ScriptTailReader from the current stream position after the
        // last trigger record.
        public static readonly MegaloSection[] H2AScriptTail = BuildH2AScriptTail();

        // --------------------------------------------------------------
        // H2AScriptTail: per-entry record shapes and MegaloVars sub-pool
        // Count widths. Matches Halo 2A/var enums.xml MegaloVars.
        // --------------------------------------------------------------
        private static MegaloSection[] BuildH2AScriptTail()
        {
            var h2aGlobalNumberRec = new MegaloSection[]
            {
                new EnumRefSection("Number", "NumericTypeRef"),
                new UIntSection("Locality", 2),
                new UIntSection("IsPersistent", 1),
            };
            var h2aGlobalTimerRec = new MegaloSection[]
            {
                new EnumRefSection("Number", "NumericTypeRef"),
            };
            var h2aGlobalTeamRec = new MegaloSection[]
            {
                new UIntSection("Team", 4),
                new UIntSection("Locality", 2),
                new UIntSection("IsPersistent", 1),
            };
            var h2aGlobalPlayerRec = new MegaloSection[]
            {
                new UIntSection("Locality", 2),
                new UIntSection("IsPersistent", 1),
            };
            var h2aGlobalObjectRec = new MegaloSection[]
            {
                new UIntSection("Locality", 2),
                new UIntSection("IsPersistent", 1),
            };

            (int, string, MegaloSection[])[] insertionBranches =
                new (int, string, MegaloSection[])[]
            {
                (0, "Used",   new MegaloSection[] { new UIntSection("Triggerref", 7) }),
                (1, "Unused", Array.Empty<MegaloSection>()),
            };

            return new MegaloSection[]
            {
                // ---- Script variable globals (after triggers) ----
                new CountSection("GlobalNumbers", 5, h2aGlobalNumberRec),  // differs: Reach 4
                new CountSection("GlobalTimers", 4, h2aGlobalTimerRec),
                new CountSection("GlobalTeams",  4, h2aGlobalTeamRec),
                new CountSection("GlobalPlayers",4, h2aGlobalPlayerRec),
                new CountSection("GlobalObjects",5, h2aGlobalObjectRec),

                // ---- MegaloVars sub-pools scoped to player/object/team ----
                new CountSection("playernumbers", 4, h2aGlobalNumberRec),
                new CountSection("playertimers",  3, h2aGlobalTimerRec),
                new CountSection("playerteams",   3, h2aGlobalTeamRec),
                new CountSection("playerplayers", 3, h2aGlobalPlayerRec),
                new CountSection("playerobjects", 3, h2aGlobalObjectRec),

                new CountSection("objectnumbers", 4, h2aGlobalNumberRec),
                new CountSection("objecttimers",  3, h2aGlobalTimerRec),
                new CountSection("objectteams",   2, h2aGlobalTeamRec),
                new CountSection("objectplayers", 3, h2aGlobalPlayerRec),
                new CountSection("objectobjects", 3, h2aGlobalObjectRec),

                new CountSection("teamnumbers", 4, h2aGlobalNumberRec),
                new CountSection("teamtimers",  3, h2aGlobalTimerRec),
                new CountSection("teamteams",   3, h2aGlobalTeamRec),
                new CountSection("teamplayers", 3, h2aGlobalPlayerRec),
                new CountSection("teamobjects", 3, h2aGlobalObjectRec),

                // H2A adds a hudwidgets Count(3) with a 4-bit location field.
                new CountSection("hudwidgets", 3, new MegaloSection[]
                {
                    new UIntSection("Location", 4),
                }),

                // InsertionPoints — 8 1-bit "Unused/Used" flags, each
                // carrying a 7-bit Triggerref payload when Used.
                new GroupSection("InsertionPoints", new MegaloSection[]
                {
                    new VariantSection("Init",                1, insertionBranches),
                    new VariantSection("LocalInit",           1, insertionBranches),
                    new VariantSection("HostMigration",       1, insertionBranches),
                    new VariantSection("DoubleHostMigration", 1, insertionBranches),
                    new VariantSection("ObjectDeath",         1, insertionBranches),
                    new VariantSection("Local",               1, insertionBranches),
                    new VariantSection("Pregame",             1, insertionBranches),
                    new VariantSection("Incident",            1, insertionBranches),
                }),

                new UnverifiedSection(
                    "H2A_TailRemainder",
                    "HUD widgets / script stats / script widgets / triggers "
                    + "follow InsertionPoints in H2A. Widths not yet "
                    + "empirically verified."),
            };
        }

